    y: z.number().describe('Y 坐标'),
    z: z.number().describe('Z 坐标'),
  },
  async ({ name, x, y, z }) => {
    const result = ctrl.measureFeature('POINT', { name, x, y, z });
    return { content: [{ type: 'text', text: result }] };
  }
);

server.tool(
  'measure_circle',
  '测量圆特征',
  {
    name: z.string().describe('特征名称'),
    x: z.number().describe('圆心 X 坐标'),
    y: z.number().describe('圆心 Y 坐标'),
    z: z.number().describe('圆心 Z 坐标（投影平面高度）'),
