    j: z.number().optional().default(0).describe('法矢 J 分量'),
    k: z.number().optional().default(1).describe('法矢 K 分量'),
    points: z.number().optional().default(4).describe('测量点数'),
  },
  async (params) => {
    const result = ctrl.measureFeature('CIRCLE', params);
    return { content: [{ type: 'text', text: result }] };
  }
);

server.tool(
  'measure_plane',
  '测量平面特征',
  {
    name: z.string().describe('特征名称'),
    points: z.number().optional().default(3).describe('测量点数'),
  },
  async ({ name, points }) => {
    const result = ctrl.measureFeature('PLANE', { name, points });
    return { content: [{ type: 'text', text: result }] };
  }
);

server.tool(
  'measure_cylinder',
  '测量圆柱特征',
  {
    name: z.string().describe('特征名称'),
    x: z.number().describe('圆心 X 坐标'),
    y: z.number().describe('圆心 Y 坐标'),
    z: z.number().describe('圆心 Z 坐标'),
    diameter: z.number().describe('标称直径'),
    height: z.number().describe('圆柱高度'),
    i: z.number().optional().default(0).describe('法矢 I 分量'),
    j: z.number().optional().default(0).describe('法矢 J 分量'),
    k: z.number().optional().default(1).describe('法矢 K 分量'),
    points: z.number().optional().default(4).describe('每层测量点数'),
    layers: z.number().optional().default(2).describe('测量层数'),
  },
  async (params) => {
    const result = ctrl.measureFeature('CYLINDER', params);
    return { content: [{ type: 'text', text: result }] };
  }
);

server.tool(
  'measure_line',
  '测量直线特征',
  {
    name: z.string().describe('特征名称'),
    x1: z.number().describe('起点 X'),
